module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output reg red
);
    parameter idle = 2'b00;
    parameter s1_red = 2'b01;
    parameter s2_yellow = 2'b10;
    parameter s3_green = 2'b11;
    reg [1:0] state;
    reg [7:0] cnt;
    reg p_red, p_yellow, p_green;
    // state transition logic
    always @(*) begin
        case (state)
            idle: begin
                state = s1_red;
            end
            s1_red: begin
                if (cnt == 3) state = s3_green;
                else state = s1_red;
            end
            s2_yellow: begin
                if (cnt == 3) state = s1_red;
                else state = s2_yellow;
            end
            s3_green: begin
                if (cnt == 3) state = s2_yellow;
                else state = s3_green;
            end
        endcase
    end
    // counter logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) cnt <= 10;
        else begin
            if (pass_request && green) cnt <= 10;
            else begin
                if (!green && p_green) cnt <= 60;
                else begin
                    if (!yellow && p_yellow) cnt <= 5;
                    else begin
                        if (!red && p_red) cnt <= 10;
                        else cnt <= cnt - 1;
                    end
                end
            end
        end
    end
    // output logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            red <= 0;
            yellow <= 0;
            green <= 0;
        end
        else begin
            red <= p_red;
            yellow <= p_yellow;
            green <= p_green;
        end
    end
endmodule
